mapper.select:
SELECT USER_CD AS userCd, USER_NM AS userNm, REQ_DATE AS reqDate, SEARCH_DIV_CD AS searchDivCd, SEARCH_DIV_VAL AS searchDivVal, WARRANT_NUM AS warrantNum, START_DATE AS startDate, FILE_NM AS fileNm, FILE_URL AS fileUrl, END_DATE AS endDate, BATCH_YN AS batchYn, APPLY_YN AS applyYn, APPROVAL_REQ_ID AS approvalReqId FROM mhdb.TB_BULK_DATA_REQ WHERE 1=1
AND USER_CD = #{userCd}
AND REQ_DATE >= concat(#{reqYmd}, ' 00:00:00') AND REQ_DATE <= concat(#{reqYmd}, ' 23:59:59')
AND SEARCH_DIV_CD = #{searchDivCd}
AND WARRANT_NUM = #{warrantNum}
ORDER BY REQ_DATE
